#define BLOCK_SIZE 16

__kernel void lud_diagonal(__global float* a, __local float* local_a, const int size, const int offset) {
    int i = get_global_id(0);
    int j, k;

    if (i >= BLOCK_SIZE) return;

    // Load diagonal block into local memory
    for (int row = 0; row < BLOCK_SIZE; row++) {
        for (int col = 0; col < BLOCK_SIZE; col++) {
            local_a[row * BLOCK_SIZE + col] = a[(offset + row) * size + (offset + col)];
        }
    }
    __syncthreads();

    for (i = 0; i < BLOCK_SIZE; i++) {
        // Update upper triangle in the diagonal block
        for (j = i; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < i; k++) {
                sum += local_a[i * BLOCK_SIZE + k] * local_a[k * BLOCK_SIZE + j];
            }
            local_a[i * BLOCK_SIZE + j] -= sum;
        }

        // Compute reciprocal of diagonal element
        float diag_inv = 1.0f / local_a[i * BLOCK_SIZE + i];

        // Update lower triangle in the diagonal block
        for (j = i + 1; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (k = 0; k < i; k++) {
                sum += local_a[j * BLOCK_SIZE + k] * local_a[k * BLOCK_SIZE + i];
            }
            local_a[j * BLOCK_SIZE + i] = (local_a[j * BLOCK_SIZE + i] - sum) * diag_inv;
        }
        __syncthreads();
    }

    // Write back to global memory
    for (int row = 0; row < BLOCK_SIZE; row++) {
        for (int col = 0; col < BLOCK_SIZE; col++) {
            a[(offset + row) * size + (offset + col)] = local_a[row * BLOCK_SIZE + col];
        }
    }
}

__kernel void lud_perimeter(__global float* a, __local float* local_diag, __local float* local_work, const int size, const int offset) {
    int idx = get_global_id(0);
    int total_blocks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (total_blocks <= 0) return;
    if (idx >= 2 * total_blocks * BLOCK_SIZE) return;

    int block_idx = idx / BLOCK_SIZE;
    int inner_idx = idx % BLOCK_SIZE;

    int i, j, k;
    float sum;

    // First half: Update rows to the right of the diagonal block
    if (block_idx < total_blocks) {
        int global_row = offset + inner_idx;
        int global_col_start = offset + BLOCK_SIZE + block_idx * BLOCK_SIZE;

        // Load necessary diagonal row into local memory
        for (k = 0; k < BLOCK_SIZE; k++) {
            local_diag[k] = a[(offset + inner_idx) * size + (offset + k)];
        }
        __syncthreads();

        for (j = 0; j < BLOCK_SIZE; j++) {
            int global_col = global_col_start + j;
            sum = 0.0f;
            for (k = 0; k < inner_idx; k++) {
                sum += local_diag[k] * a[(offset + k) * size + global_col];
            }
            a[global_row * size + global_col] -= sum;
        }
    } 
    // Second half: Update columns below the diagonal block
    else {
        int col_block = block_idx - total_blocks;
        int global_col = offset + inner_idx;
        int global_row_start = offset + BLOCK_SIZE + col_block * BLOCK_SIZE;

        // Load diagonal column into local memory
        for (k = 0; k < BLOCK_SIZE; k++) {
            local_diag[k] = a[(offset + k) * size + (offset + inner_idx)];
        }
        __syncthreads();

        float diag_val = a[(offset + inner_idx) * size + (offset + inner_idx)];

        for (i = 0; i < BLOCK_SIZE; i++) {
            int global_row = global_row_start + i;
            sum = 0.0f;
            for (k = 0; k < inner_idx; k++) {
                sum += a[global_row * size + (offset + k)] * local_diag[k];
            }
            a[global_row * size + global_col] = (a[global_row * size + global_col] - sum) / diag_val;
        }
    }
}

__kernel void lud_internal(__global float* a, __local float* local_row_block, __local float* local_col_block, const int size, const int offset) {
    int gx = get_global_id(0);
    int gy = get_global_id(1);

    int num_blocks = (size - offset - BLOCK_SIZE) / BLOCK_SIZE;

    if (num_blocks <= 0) return;

    int total_width = num_blocks * BLOCK_SIZE;
    if (gx >= total_width || gy >= total_width) return;

    // Determine block coordinates
    int block_x = gx / BLOCK_SIZE;
    int block_y = gy / BLOCK_SIZE;
    int local_x = gx % BLOCK_SIZE;
    int local_y = gy % BLOCK_SIZE;

    int global_row = offset + BLOCK_SIZE + block_y * BLOCK_SIZE + local_y;
    int global_col = offset + BLOCK_SIZE + block_x * BLOCK_SIZE + local_x;

    int data_3 = offset + BLOCK_SIZE + block_y * BLOCK_SIZE;
    int data_13 = offset + BLOCK_SIZE + block_x * BLOCK_SIZE;

    // Load val_11: Rows (data_3 .. data_3+BS-1), Columns (offset .. offset+BS-1)
    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            local_row_block[i * BLOCK_SIZE + j] = a[(data_3 + i) * size + (offset + j)];
        }
    }

    // Load tmp_6: Rows (offset .. offset+BS-1), Columns (data_13 .. data_13+BS-1)
    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            local_col_block[i * BLOCK_SIZE + j] = a[(offset + i) * size + (data_13 + j)];
        }
    }
    __syncthreads();

    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += local_row_block[local_y * BLOCK_SIZE + k] * local_col_block[k * BLOCK_SIZE + local_x];
    }

    a[global_row * size + global_col] -= sum;
}
